--Auxiliary function: Search for event parameters through the engine event key
--= = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = = =

---@type table<string, table>
M.key_map = {}

--Build the mapping of key -> event_params
for name, cfg in pairs(M.config) do
    if cfg.key and cfg.event_params then
        M.key_map[cfg.key] = cfg.event_params
    end
end

---Obtain the list of event parameters through the engine event key
---@param event_key string Engine event key (such as "ET_GAME_INIT")
---@return table: nil event_params event parameter list
function M.get_event_params_by_key(event_key)
    return M.key_map[event_key]
end

return M
